import { useEffect, useState } from 'react';
import { supabase } from '../supabase';
import { useAuth } from '../context/AuthContext';
import { CATEGORIES, ASSET_TYPES, CAT_COLORS, STATUS_COLORS, fmtDate, Icon, Badge, Btn, GhostBtn, IconBtn, Modal, Field, Empty, PageHeader, inputStyle, selectStyle, useToast, Toast } from './ui';
import { LoadingPage } from './Dashboard';

export default function Assets() {
  const { can } = useAuth();
  const [assets, setAssets]   = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch]   = useState('');
  const [filterCat, setFilterCat] = useState('all');
  const [showForm, setShowForm] = useState(false);
  const [editId, setEditId]   = useState(null);
  const { toast, show } = useToast();
  const blank = { id:'',name:'',category:'asphalt',type:'truck',year:'',make:'',model:'',status:'active',notes:'' };
  const [form, setForm] = useState(blank);

  useEffect(()=>{ load(); },[]);

  const load = async () => {
    const { data } = await supabase.from('assets').select('*').order('id');
    setAssets(data||[]);
    setLoading(false);
  };

  const openNew  = () => { setForm(blank); setEditId(null); setShowForm(true); };
  const openEdit = (a) => { setForm({...a}); setEditId(a.id); setShowForm(true); };

  const save = async () => {
    if (!form.id||!form.name) return show('Asset ID and Name are required','error');
    if (editId) {
      const { error } = await supabase.from('assets').update({...form}).eq('id',editId);
      if (error) return show(error.message,'error');
      show('Asset updated');
    } else {
      const { error } = await supabase.from('assets').insert({...form});
      if (error) return show(error.message,'error');
      show('Asset added');
    }
    setShowForm(false);
    load();
  };

  const remove = async (id) => {
    if (!window.confirm('Delete this asset? This cannot be undone.')) return;
    await supabase.from('assets').delete().eq('id',id);
    show('Asset removed');
    load();
  };

  const filtered = assets.filter(a =>
    (filterCat==='all'||a.category===filterCat) &&
    (a.id.toLowerCase().includes(search.toLowerCase())||
     a.name.toLowerCase().includes(search.toLowerCase())||
     (a.make||'').toLowerCase().includes(search.toLowerCase()))
  );

  if (loading) return <LoadingPage/>;

  return (
    <div style={{padding:32}}>
      <PageHeader title="Assets" subtitle={`${assets.length} assets registered`}
        action={can('assets') && <Btn icon="plus" onClick={openNew}>Add Asset</Btn>}/>

      <div style={{display:'flex',gap:12,marginBottom:20,flexWrap:'wrap'}}>
        <div style={{position:'relative',flex:'1 1 200px'}}>
          <div style={{position:'absolute',left:12,top:'50%',transform:'translateY(-50%)',color:'#475569'}}><Icon name="search" size={15}/></div>
          <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="Search by ID, name, or make…" style={{...inputStyle,paddingLeft:36}}/>
        </div>
        <select value={filterCat} onChange={e=>setFilterCat(e.target.value)} style={selectStyle}>
          <option value="all">All Categories</option>
          {CATEGORIES.map(c=><option key={c} value={c}>{c}</option>)}
        </select>
      </div>

      <div style={{background:'#0f1218',borderRadius:12,border:'1px solid #1e2530',overflow:'hidden'}}>
        <table style={{width:'100%',borderCollapse:'collapse',fontSize:13.5}}>
          <thead>
            <tr style={{borderBottom:'1px solid #1e2530'}}>
              {['Asset ID','Name','Category','Type','Year / Make / Model','Status', can('assets') && 'Actions'].filter(Boolean).map(h=>(
                <th key={h} style={{padding:'12px 16px',textAlign:'left',fontSize:11,fontWeight:600,letterSpacing:1.5,textTransform:'uppercase',color:'#475569'}}>{h}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {filtered.length===0 && <tr><td colSpan={7} style={{padding:32,textAlign:'center',color:'#475569'}}>No assets found</td></tr>}
            {filtered.map(a=>(
              <tr key={a.id} style={{borderBottom:'1px solid #1e2530'}}
                onMouseEnter={e=>e.currentTarget.style.background='#111827'}
                onMouseLeave={e=>e.currentTarget.style.background='transparent'}
              >
                <td style={{padding:'12px 16px'}}><span style={{fontFamily:"'DM Mono',monospace",fontSize:12,color:'#f97316',fontWeight:600}}>{a.id}</span></td>
                <td style={{padding:'12px 16px',fontWeight:500}}>{a.name}</td>
                <td style={{padding:'12px 16px'}}><Badge text={a.category} color={CAT_COLORS[a.category]||'#64748b'}/></td>
                <td style={{padding:'12px 16px',color:'#94a3b8',textTransform:'capitalize'}}>{a.type}</td>
                <td style={{padding:'12px 16px',color:'#94a3b8'}}>{[a.year,a.make,a.model].filter(Boolean).join(' · ')||'—'}</td>
                <td style={{padding:'12px 16px'}}>
                  <span style={{display:'inline-flex',alignItems:'center',gap:5,fontSize:12,fontWeight:500,color:STATUS_COLORS[a.status||'active']||'#22c55e'}}>
                    <span style={{width:6,height:6,borderRadius:'50%',background:STATUS_COLORS[a.status||'active'],display:'inline-block'}}/>
                    {(a.status||'active').toUpperCase()}
                  </span>
                </td>
                {can('assets') && (
                  <td style={{padding:'12px 16px'}}>
                    <div style={{display:'flex',gap:6}}>
                      <IconBtn icon="edit" title="Edit" onClick={()=>openEdit(a)}/>
                      <IconBtn icon="trash" title="Delete" color="#ef4444" onClick={()=>remove(a.id)}/>
                    </div>
                  </td>
                )}
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {showForm && (
        <Modal title={editId?'Edit Asset':'Add New Asset'} onClose={()=>setShowForm(false)}>
          <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:14}}>
            <Field label="Asset ID *"><input style={inputStyle} value={form.id} onChange={e=>setForm(p=>({...p,id:e.target.value}))} placeholder="e.g. LAN-005" disabled={!!editId}/></Field>
            <Field label="Name *"><input style={inputStyle} value={form.name} onChange={e=>setForm(p=>({...p,name:e.target.value}))}/></Field>
            <Field label="Category"><select style={selectStyle} value={form.category} onChange={e=>setForm(p=>({...p,category:e.target.value}))}>{CATEGORIES.map(c=><option key={c}>{c}</option>)}</select></Field>
            <Field label="Type"><select style={selectStyle} value={form.type} onChange={e=>setForm(p=>({...p,type:e.target.value}))}>{ASSET_TYPES.map(t=><option key={t}>{t}</option>)}</select></Field>
            <Field label="Year"><input style={inputStyle} value={form.year} onChange={e=>setForm(p=>({...p,year:e.target.value}))} placeholder="2022"/></Field>
            <Field label="Status">
              <select style={selectStyle} value={form.status||'active'} onChange={e=>setForm(p=>({...p,status:e.target.value}))}>
                <option value="active">Active</option>
                <option value="out of service">Out of Service</option>
                <option value="maintenance">In Maintenance</option>
                <option value="retired">Retired</option>
              </select>
            </Field>
            <Field label="Make"><input style={inputStyle} value={form.make} onChange={e=>setForm(p=>({...p,make:e.target.value}))}/></Field>
            <Field label="Model"><input style={inputStyle} value={form.model} onChange={e=>setForm(p=>({...p,model:e.target.value}))}/></Field>
            <Field label="Notes" fullWidth><textarea style={{...inputStyle,height:72,resize:'vertical'}} value={form.notes} onChange={e=>setForm(p=>({...p,notes:e.target.value}))}/></Field>
          </div>
          <div style={{display:'flex',justifyContent:'flex-end',gap:10,marginTop:20}}>
            <GhostBtn onClick={()=>setShowForm(false)}>Cancel</GhostBtn>
            <Btn onClick={save}>Save Asset</Btn>
          </div>
        </Modal>
      )}
      <Toast toast={toast}/>
    </div>
  );
}
